"""Calculator module — core arithmetic operations.

Refactored to use dispatch table for cleaner operation routing.
"""


def add(a, b):
    return a + b


def subtract(a, b):
    return a - b


def multiply(a, b):
    return a * b


def divide(a, b):
    if b == 0:
        raise ValueError("Cannot divide by zero")
    return a / b


def int_divide(a, b):
    if b == 0:
        raise ValueError("Cannot divide by zero")
    return int(a / b)


def power(a, b):
    return a ** b


def modulo(a, b):
    if b == 0:
        raise ValueError("Cannot compute modulo with zero")
    return a % b


# Operation dispatch table — cleaner than if/elif chain
_OPERATIONS = {
    "add": add,
    "sub": subtract,
    "mul": multiply,
    "div": divide,
    "intdiv": int_divide,
    "pow": power,
    "mod": modulo,
}


def compute(operation, a, b):
    """Dispatch an operation by name using lookup table."""
    func = _OPERATIONS.get(operation)
    if func is None:
        raise ValueError(f"Unknown operation: {operation}")
    return func(a, b)
